def __decode(data):
    # Convert back from ASCII numbers
    decoded = ''.join(chr(int(x)) for x in data.split(','))
    
    # Decode base85
    decoded = __import__('base64').b85decode(decoded.encode()).decode()
    
    # Decode ROT13
    decoded = __import__('codecs').decode(decoded, 'rot13')
    
    # Convert hex back to bytes
    decoded = bytes.fromhex(decoded)
    
    # Decompress
    decoded = __import__('zlib').decompress(decoded)
    
    return decoded.decode()

exec(__decode(__encoded))
